const allItems = $input.all().map(i => i.json);
const rawRows = allItems.filter(i => i['ID-TIME'] !== undefined);
const summaryRows = allItems.filter(i => i['MesNum'] !== undefined || i['Mes'] !== undefined);

const now = new Date();
const currentYear = now.getFullYear();
const prevMonthDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonth = prevMonthDate.getMonth();
const prevMonthYear = prevMonthDate.getFullYear();
const monthNames = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const prevMonthName = monthNames[prevMonth];
const currentMonthName = monthNames[now.getMonth()];

function parseImporte(val) {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return val;
  const clean = String(val).replace(/\$/g,'').replace(/\./g,'').replace(',','.').trim();
  const n = parseFloat(clean);
  return isNaN(n) ? 0 : n;
}

function parseDate(val) {
  if (!val) return null;
  const m = String(val).trim().match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (!m) return null;
  return new Date(parseInt(m[3]), parseInt(m[2])-1, parseInt(m[1]));
}

function normalizeCategory(cat) {
  if (!cat) return 'Sin Categoría';
  const s = String(cat).trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ');
  const map = [
    [/finanzas.*(futuro|futr?)/,'Finanzas y Futuro'],
    [/honorarios|venta.*servicio|servicio.*venta/,'Honorarios Profesionales'],
    [/supermercado|almacen|aliment|viveres|verdura|pescad/,'Alimentación'],
    [/suscri|servicio.*ia|ia.*servicio|openrouter|claude|chatgpt|digital/,'Suscripciones Digitales'],
    [/gimnasio|deporte|suplemento|salud/,'Salud y Deporte'],
    [/impuesto|afip|arba|arca|fiscal/,'Impuestos'],
    [/telefon|celular|movil/,'Telefonía'],
    [/mascota|veterinar/,'Mascotas'],
    [/limpieza|mantenimiento|vivienda|materiale|bicarbonato/,'Vivienda y Servicios'],
    [/gastos.*(operativo|oper)|operativo/,'Gastos Operativos'],
    [/estilo|personal|ropa|indument/,'Estilo de Vida'],
    [/trading|inversion|ganancia/,'Inversiones y Trading'],
    [/capital.?inicial|saldo.?inicial/,'Capital Inicial']
  ];
  for (const [p,l] of map) if (p.test(s)) return l;
  return String(cat).trim().replace(/\b\w/g,c=>c.toUpperCase());
}

function cleanKeys(row) {
  const c = {};
  for (const k of Object.keys(row)) c[k.trim()] = row[k];
  return c;
}

const parsed = rawRows.map(row => {
  const r = cleanKeys(row);
  const date = parseDate(r['ID-TIME']);
  return {
    date,
    tipo: String(r['Tipo']||'').trim(),
    persona: String(r['Persona']||'').trim(),
    categoria: normalizeCategory(r['Categoría']||r['Categoria']||r['Categor\u00eda']),
    importe: parseImporte(r['Importe'])
  };
}).filter(r => r.date && r.importe > 0);

function calcStats(data) {
  const ingresos = data.filter(r=>r.tipo==='Ingreso'&&r.categoria!=='Capital Inicial').reduce((s,r)=>s+r.importe,0);
  const egresos  = data.filter(r=>r.tipo==='Egreso').reduce((s,r)=>s+r.importe,0);
  const byCategoria = {};
  data.filter(r=>r.tipo==='Egreso').forEach(r=>{ byCategoria[r.categoria]=(byCategoria[r.categoria]||0)+r.importe; });
  const byPersona = {};
  data.filter(r=>r.tipo==='Egreso'&&r.persona&&r.persona!=='Sistema').forEach(r=>{ byPersona[r.persona]=(byPersona[r.persona]||0)+r.importe; });
  // NUEVO: ingresos por persona
  const byPersonaIngresos = {};
  data.filter(r=>r.tipo==='Ingreso'&&r.categoria!=='Capital Inicial'&&r.persona&&r.persona!=='Sistema').forEach(r=>{ byPersonaIngresos[r.persona]=(byPersonaIngresos[r.persona]||0)+r.importe; });
  // NUEVO: categorías por persona
  const byPersonaCategorias = {};
  data.filter(r=>r.tipo==='Egreso'&&r.persona&&r.persona!=='Sistema').forEach(r=>{
    if(!byPersonaCategorias[r.persona]) byPersonaCategorias[r.persona]={};
    byPersonaCategorias[r.persona][r.categoria]=(byPersonaCategorias[r.persona][r.categoria]||0)+r.importe;
  });
  return { ingresos, egresos, balance: ingresos-egresos, byCategoria, byPersona, byPersonaIngresos, byPersonaCategorias };
}

const yearData = parsed.filter(r => r.date.getFullYear() === currentYear);
const monthlyEvolution = {};
for (let m = 0; m < 12; m++) {
  const mData = yearData.filter(r => r.date.getMonth() === m);
  if (mData.length > 0) {
    const s = calcStats(mData);
    monthlyEvolution[m] = { 
 ingresos: s.ingresos,
 egresos: s.egresos,
 balance: s.balance,
 byCategoria: s.byCategoria,
 byPersona: s.byPersona,
 byPersonaIngresos: s.byPersonaIngresos,
 byPersonaCategorias: s.byPersonaCategorias
};
  }
}

const prevMonthData = parsed.filter(r => r.date.getFullYear() === prevMonthYear && r.date.getMonth() === prevMonth);
const prevStats = calcStats(prevMonthData);

const newSummaryRow = {
  Mes: prevMonthName,
  Anio: prevMonthYear,
  MesNum: prevMonth + 1,
  Ingresos: prevStats.ingresos,
  Egresos: prevStats.egresos,
  Balance: prevStats.balance,
  ByCategoria: JSON.stringify(prevStats.byCategoria),
  ByPersona: JSON.stringify(prevStats.byPersona),
  ByPersonaIngresos: JSON.stringify(prevStats.byPersonaIngresos)
};

const historicalMonths = {};

// 1) Tomar SOLO lo que está guardado en el sheet
summaryRows.forEach(row => {

  const r = cleanKeys(row);

  const anio = parseInt(r['Anio']||r['Año']||0);
  const mesNum = parseInt(r['MesNum']||0);

  if (!anio || !mesNum) return;

  const key = `${anio}-${mesNum}`;

  let byCategoria = {};
  let byPersona = {};

  try { byCategoria = JSON.parse(r['ByCategoria']||'{}'); } catch(e){}
  try { byPersona   = JSON.parse(r['ByPersona']||'{}');   } catch(e){}

  historicalMonths[key] = {
    mes: String(r['Mes']||''),
    anio,
    mesNum,
    ingresos: parseImporte(r['Ingresos']),
    egresos: parseImporte(r['Egresos']),
    balance: parseImporte(r['Balance']),
    byCategoria,
    byPersona
  };

});


// 2) Solo si el mes NO existe usar el calculado
const currentKey = `${prevMonthYear}-${prevMonth+1}`;

if (!historicalMonths[currentKey]) {

 historicalMonths[currentKey] = {

 mes: prevMonthName,
 anio: prevMonthYear,
 mesNum: prevMonth+1,

 ingresos: prevStats.ingresos,
 egresos: prevStats.egresos,
 balance: prevStats.balance,

 byCategoria: prevStats.byCategoria,
 byPersona: prevStats.byPersona

 };

}

const yearMonths = Object.values(historicalMonths).filter(m => m.anio === currentYear);
const yearIngresos = yearMonths.reduce((s,m)=>s+m.ingresos,0);
const yearEgresos  = yearMonths.reduce((s,m)=>s+m.egresos,0);
const yearBalance  = yearIngresos - yearEgresos;
const yearByCat = {};
yearMonths.forEach(m => { Object.entries(m.byCategoria).forEach(([k,v]) => { yearByCat[k]=(yearByCat[k]||0)+v; }); });

const allMonthsAvailable = Object.keys(monthlyEvolution).map(Number).sort((a,b)=>a-b);

return [{
  json: {
    prevMonth, prevMonthYear, prevMonthName, currentMonthName, currentYear,
    monthStats: { ingresos: prevStats.ingresos, egresos: prevStats.egresos, balance: prevStats.balance, byCategoria: prevStats.byCategoria, byPersona: prevStats.byPersona, byPersonaCategorias: prevStats.byPersonaCategorias },
    yearStats: { ingresos: yearIngresos, egresos: yearEgresos, balance: yearBalance, byCategoria: yearByCat },
    monthlyEvolution, monthNames, allMonthsAvailable, newSummaryRow
  }
}];

const allItems = $input.first().json;
const { monthlyEvolution, monthNames, currentYear } = allItems;

const mergeItems = $('Merge').all().map(i => i.json);
const summaryRows = mergeItems.filter(i => i['MesNum'] !== undefined || i['Mes'] !== undefined);

const existing = summaryRows.map(r => {
  const c = {};
  for (const k of Object.keys(r)) c[k.trim()] = r[k];
  return c;
});

const savedKeys = new Set(existing.map(r => `${r['Anio']||r['Año']}-${r['MesNum']}`));

const rowsToAppend = [];
for (const mIdx of Object.keys(monthlyEvolution).map(Number).sort((a,b)=>a-b)) {
  const key = `${currentYear}-${mIdx+1}`;
  if (savedKeys.has(key)) continue;
  const m = monthlyEvolution[mIdx];
  rowsToAppend.push({
  Mes: monthNames[mIdx],
  Anio: currentYear,
  MesNum: mIdx + 1,
  Ingresos: m.ingresos,
  Egresos: m.egresos,
  Balance: m.balance,
  ByCategoria: JSON.stringify(m.byCategoria),
  ByPersona: JSON.stringify(m.byPersona),
  ByPersonaIngresos: JSON.stringify(m.byPersonaIngresos),
  ByPersonaCategorias: JSON.stringify(m.byPersonaCategorias || {})
});
}

if (rowsToAppend.length > 0) {
  return rowsToAppend.map(r => ({ json: r }));
}
return [{ json: { _skip: true } }];

const data = $('Process Financial Data').first().json;
let summaryRows;
try {
  summaryRows = $('Re-Read Monthly Summary').all().map(i => i.json);
  if (!summaryRows || summaryRows.length === 0) throw new Error('empty');
} catch(e) {
  summaryRows = $('Get Monthly Summary Sheet').all().map(i => i.json);
}

function parseImporte(val){
 if(!val) return 0;
 if(typeof val==='number') return val;
 return parseFloat(String(val).replace(/\./g,'').replace(',','.'))||0;
}

const cleanRow=r=>{
 const c={};
 Object.keys(r).forEach(k=>c[k.trim()]=r[k]);
 return c;
};

const summaryMonths = summaryRows
 .map(cleanRow)
 .filter(r=>parseInt(r.Anio)===data.currentYear)
 .sort((a,b)=>parseInt(a.MesNum)-parseInt(b.MesNum));
const { prevMonthName, prevMonth, currentMonthName, currentYear, monthStats, yearStats, monthlyEvolution, monthNames, allMonthsAvailable } = data;

const monthlyLabels   = summaryMonths.map(m=>m.Mes);
const monthlyIngresos = summaryMonths.map(m=>parseImporte(m.Ingresos));
const monthlyEgresos  = summaryMonths.map(m=>parseImporte(m.Egresos));
const monthlyBalance  = summaryMonths.map(m=>parseImporte(m.Balance));

// Personas
const personas = [...new Set(
 summaryMonths.flatMap(m=>{
  try{ return Object.keys(JSON.parse(m.ByPersona||'{}')); }catch(e){ return []; }
 })
)].filter(p=>p!=='Sistema');

// Monthly by persona (for bar chart per persona)
const monthlyByPersona = {};
personas.forEach(p=>{
 monthlyByPersona[p]={
  ingresos: summaryMonths.map(m=>{
   try{ return JSON.parse(m.ByPersonaIngresos||'{}')[p]||0; }catch(e){ return 0; }
  }),
  egresos: summaryMonths.map(m=>{
   try{ return JSON.parse(m.ByPersona||'{}')[p]||0; }catch(e){ return 0; }
  })
 };
 monthlyByPersona[p].balance = monthlyByPersona[p].ingresos.map((v,i)=>v-monthlyByPersona[p].egresos[i]);
});

// ByPersonaCategorias per summary month (for per-persona category view)
const monthlyByPersonaCategorias = {};
summaryMonths.forEach((m, idx) => {
 try {
  monthlyByPersonaCategorias[idx] = JSON.parse(m.ByPersonaCategorias || '{}');
 } catch(e) {
  monthlyByPersonaCategorias[idx] = {};
 }
});

const monthSelectorOptions = allMonthsAvailable.map(m =>
  `<option value="${m}" ${m===prevMonth?'selected':''}>${monthNames[m]}</option>`
).join('');

function fmtARS(n) {
  if (Math.abs(n) >= 1000000) return '$' + (n/1000000).toFixed(1) + 'M';
  if (Math.abs(n) >= 1000) return '$' + Math.round(n/1000) + 'K';
  return '$' + Math.round(n);
}
function fmtFull(n) {
  return new Intl.NumberFormat('es-AR',{style:'currency',currency:'ARS',minimumFractionDigits:0,maximumFractionDigits:0}).format(n);
}

const tasa = monthStats.ingresos > 0 ? Math.round((monthStats.balance / monthStats.ingresos) * 100) : 0;
const tasaYear = yearStats.ingresos > 0 ? Math.round((yearStats.balance / yearStats.ingresos) * 100) : 0;
