      <div class="date-badge">1 de ${currentMonthName} ${currentYear}<\/div>
      <div class="pill">
        <label>Ver mes<\/label>
        <select id="msel" onchange="updMonth(this.value)">${monthSelectorOptions}<\/select>
      <\/div>
    <\/div>
  <\/header>

  <div class="persona-tabs">
    <button class="ptab active" onclick="updPersona('todos')" id="tab-todos">👥 Todos<\/button>
    ${personas.map((p,i)=>`<button class="ptab" onclick="updPersona('${p}')" id="tab-${p.toLowerCase()}">${p}<\/button>`).join('')}
  <\/div>

  <div class="kpi-grid">
    <div class="kpi">
      <div class="kpi-label">Ingresos del mes<\/div>
      <div class="kpi-value green" id="kIngresos">${fmtARS(monthStats.ingresos)}<\/div>
      <div class="kpi-sub" id="kIngLabel">${prevMonthName} ${currentYear}<\/div>
      <div class="kpi-badge up">↑ Ingreso<\/div>
      <div class="kpi-accent green"><\/div>
    <\/div>
    <div class="kpi">
      <div class="kpi-label">Egresos del mes<\/div>
      <div class="kpi-value red" id="kEgresos">${fmtARS(monthStats.egresos)}<\/div>
      <div class="kpi-sub" id="kEgrLabel">${prevMonthName} ${currentYear}<\/div>
      <div class="kpi-badge down">↓ Gasto<\/div>
      <div class="kpi-accent red"><\/div>
    <\/div>
    <div class="kpi">
      <div class="kpi-label">Balance mensual<\/div>
      <div class="kpi-value ${monthStats.balance>=0?'green':'red'}" id="kBalance">${fmtARS(monthStats.balance)}<\/div>
      <div class="kpi-sub">Resultado neto<\/div>
      <div class="kpi-badge ${monthStats.balance>=0?'up':'down'}" id="kBalBadge">${monthStats.balance>=0?'Positivo':'Negativo'}<\/div>
      <div class="kpi-accent blue"><\/div>
    <\/div>
    <div class="kpi">
      <div class="kpi-label">Tasa de ahorro<\/div>
      <div class="kpi-value blue" id="kTasa">${tasa}%<\/div>
      <div class="kpi-sub">Del ingreso conservado<\/div>
      <div class="kpi-badge neutral" id="kTasaBadge">${tasa>=30?'Excelente':tasa>=15?'Bueno':'Mejorable'}<\/div>
      <div class="kpi-accent amber"><\/div>
    <\/div>
  <\/div>

  <div class="main-grid">
    <div class="card">
      <div class="section-title" id="barTitle">Evolución ${currentYear}<\/div>
      <div class="section-sub" id="barSub">Ingresos vs egresos por mes<\/div>
      <div style="position:relative;height:240px;"><canvas id="barChart"><\/canvas><\/div>
    <\/div>
    <div class="card">
      <div class="section-title">Distribución<\/div>
      <div class="section-sub" id="pieSub">${prevMonthName} · ingresos vs egresos<\/div>
      <div style="position:relative;height:190px;display:flex;align-items:center;justify-content:center;"><canvas id="pieChart"><\/canvas><\/div>
      <div style="display:flex;justify-content:center;gap:20px;margin-top:14px;">
        <div style="display:flex;align-items:center;gap:6px;"><span style="width:9px;height:9px;border-radius:50%;background:#00C896;display:inline-block;"><\/span><span style="font-size:12px;color:var(--mid);">Ingresos<\/span><\/div>
        <div style="display:flex;align-items:center;gap:6px;"><span style="width:9px;height:9px;border-radius:50%;background:#FF3B5C;display:inline-block;"><\/span><span style="font-size:12px;color:var(--mid);">Egresos<\/span><\/div>
      <\/div>
    <\/div>
  <\/div>

  <div class="bottom-grid">
    <div class="card">
      <div class="section-title">Top Categorías<\/div>
      <div class="section-sub" id="catSub">${prevMonthName} · egresos<\/div>
      <div class="cat-list" id="catList"><\/div>
    <\/div>
    <div class="card">
      <div class="section-title">Por Persona<\/div>
      <div class="section-sub" id="psSub">${prevMonthName} · desglose<\/div>
      <div class="persona-split" id="personaSplit"><\/div>
    <\/div>
    <div class="card">
      <div class="section-title">Tasa de Ahorro<\/div>
      <div class="section-sub" id="arcSub">${prevMonthName} · del ingreso<\/div>
      <div class="savings-wrap">
        <div class="arc-container">
          <svg width="180" height="100" viewBox="0 0 180 100">
            <path d="M10,100 A80,80 0 0,1 170,100" fill="none" stroke="#E5E7EB" stroke-width="12" stroke-linecap="round"/>
            <path id="arcPath" d="M10,100 A80,80 0 0,1 170,100" fill="none" stroke="url(#arcGrad)" stroke-width="12" stroke-linecap="round" stroke-dasharray="251.2" stroke-dashoffset="${251.2-(251.2*Math.min(Math.max(tasa,0),100)/100)}"/>
            <defs><linearGradient id="arcGrad" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" stop-color="#4F6EF7"/><stop offset="100%" stop-color="#00C896"/><\/linearGradient><\/defs>
          <\/svg>
          <div class="arc-center"><div class="arc-pct" id="arcPct">${tasa}%<\/div><\/div>
        <\/div>
        <div class="savings-detail">
          <div class="sd-item"><div class="sd-label">Ingresado<\/div><div class="sd-val" style="color:var(--green)" id="sdIng">${fmtARS(monthStats.ingresos)}<\/div><\/div>
          <div class="sd-item"><div class="sd-label">Gastado<\/div><div class="sd-val" style="color:var(--red)" id="sdEgr">${fmtARS(monthStats.egresos)}<\/div><\/div>
        <\/div>
      <\/div>
    <\/div>
  <\/div>

  <div class="year-strip">
    <div class="ys-item">
      <div class="ys-label">Ingresos ${currentYear}<\/div>
      <div class="ys-val green" id="ysIng">${fmtARS(yearStats.ingresos)}<\/div>
      <div class="ys-sub">acumulado anual<\/div>
    <\/div>
    <div class="ys-item">
      <div class="ys-label">Egresos ${currentYear}<\/div>
      <div class="ys-val red" id="ysEgr">${fmtARS(yearStats.egresos)}<\/div>
      <div class="ys-sub">acumulado anual<\/div>
    <\/div>
    <div class="ys-item">
      <div class="ys-label">Balance ${currentYear}<\/div>
      <div class="ys-val ${yearStats.balance>=0?'green':'red'}" id="ysBal">${fmtARS(yearStats.balance)}<\/div>
      <div class="ys-sub" id="ysBalSub">tasa de ahorro ${tasaYear}%<\/div>
    <\/div>
  <\/div>

  <footer>LAUFAB · Dashboard Financiero ${currentYear} · Generado el 1 de ${currentMonthName}<\/footer>
<\/div>

<script>
const MN=${JSON.stringify(monthNames)};
const AD=${JSON.stringify(monthlyEvolution)};
const YEAR=${currentYear};
const ML=${JSON.stringify(monthlyLabels)};
const MI=${JSON.stringify(monthlyIngresos)};
const ME=${JSON.stringify(monthlyEgresos)};
const MB=${JSON.stringify(monthlyBalance)};
const CC=${JSON.stringify(catColors)};
const PC_COLORS=${JSON.stringify(personaColors)};
const PERSONAS=${JSON.stringify(personas)};
const MBP=${JSON.stringify(monthlyByPersona)};
const MBPC=${JSON.stringify(monthlyByPersonaCategorias)};

let currentMonth=${prevMonth};
let currentPersona='todos';
let PC,BC;

function fmtARS(n){if(Math.abs(n)>=1000000)return'$'+(n/1000000).toFixed(1)+'M';if(Math.abs(n)>=1000)return'$'+Math.round(n/1000)+'K';return'$'+Math.round(n);}
function fmtFull(n){return new Intl.NumberFormat('es-AR',{style:'currency',currency:'ARS',minimumFractionDigits:0}).format(n);}

function getFilteredData(monthIdx, persona) {
  const d = AD[monthIdx];
  if (!d) return { ingresos:0, egresos:0, balance:0, byCategoria:{}, byPersona:{}, byPersonaIngresos:{} };
  if (persona === 'todos') return d;
  const personaCats = d.byPersonaCategorias?.[persona] || {};
  return {
    ingresos: d.byPersonaIngresos?.[persona] || 0,
    egresos: d.byPersona?.[persona] || 0,
    balance: (d.byPersonaIngresos?.[persona]||0) - (d.byPersona?.[persona]||0),
    byCategoria: personaCats,
    byPersona: { [persona]: d.byPersona?.[persona]||0 },
    byPersonaIngresos: { [persona]: d.byPersonaIngresos?.[persona]||0 }
  };
}

function getYearFiltered(persona) {
  let ing=0,egr=0;
  Object.values(AD).forEach(d=>{
    if(persona==='todos'){ing+=d.ingresos||0;egr+=d.egresos||0;}
    else{ing+=(d.byPersonaIngresos?.[persona]||0);egr+=(d.byPersona?.[persona]||0);}
  });
  return {ingresos:ing,egresos:egr,balance:ing-egr};
}

function buildCatList(byCategoria){
  const entries=Object.entries(byCategoria).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const maxVal=entries[0]?.[1]||1;
  if(!entries.length) return '<div style="color:#9CA3AF;font-size:13px;padding:8px 0;">Sin datos<\/div>';
  return entries.map(([name,val],i)=>{
    const pct=Math.round((val/maxVal)*100);
    return '<div class="cat-item"><div class="cat-dot" style="background:'+CC[i%CC.length]+';"><\/div><div class="cat-name">'+name+'<\/div><div class="cat-bar-wrap"><div class="cat-bar" style="width:'+pct+'%;background:'+CC[i%CC.length]+';"><\/div><\/div><div class="cat-amt">'+fmtARS(val)+'<\/div><\/div>';
  }).join('');
}

function buildPersonaSplit(d, persona, mn){
  if(persona !== 'todos') return '<div style="color:#9CA3AF;font-size:12px;padding:8px 0;">Vista individual activa · '+persona+'<\/div>';
  const totalEgr = Object.values(d.byPersona||{}).reduce((s,v)=>s+v,0);
  return PERSONAS.map((p,i)=>{
    const pIng = d.byPersonaIngresos?.[p]||0;
    const pEgr = d.byPersona?.[p]||0;
    const pBal = pIng - pEgr;
    const pct = totalEgr > 0 ? Math.round((pEgr/totalEgr)*100) : 0;
    const initials = p.substring(0,2).toUpperCase();
    const col = PC_COLORS[i%PC_COLORS.length];
    return '<div class="ps-card">'+
      '<div class="ps-header">'+
        '<div class="ps-avatar" style="background:'+col+'22;color:'+col+';">'+initials+'<\/div>'+
        '<div class="ps-name">'+p+'<\/div>'+
        '<div class="ps-pct">'+pct+'% del gasto<\/div>'+
      '<\/div>'+
      '<div class="ps-row">'+
        '<div class="ps-stat"><div class="ps-stat-label">Ingresos<\/div><div class="ps-stat-val" style="color:#00C896;">'+fmtARS(pIng)+'<\/div><\/div>'+
        '<div class="ps-stat"><div class="ps-stat-label">Egresos<\/div><div class="ps-stat-val" style="color:#FF3B5C;">'+fmtARS(pEgr)+'<\/div><\/div>'+
        '<div class="ps-stat"><div class="ps-stat-label">Balance<\/div><div class="ps-stat-val" style="color:'+(pBal>=0?'#00C896':'#FF3B5C')+';">'+fmtARS(pBal)+'<\/div><\/div>'+
      '<\/div>'+
      '<div class="ps-bar-wrap"><div class="ps-bar" style="width:'+pct+'%;background:'+col+';"><\/div><\/div>'+
    '<\/div>';
  }).join('');
}

function updateArc(t){
  const c=Math.min(Math.max(t,0),100);
  const p=document.getElementById('arcPath');
  if(p)p.setAttribute('stroke-dashoffset',251.2-(251.2*c/100));
  const ap=document.getElementById('arcPct');
  if(ap)ap.textContent=c+'%';
}

function renderAll(monthIdx, persona){
  const d = getFilteredData(monthIdx, persona);
  const mn = MN[monthIdx];
  const ing=d.ingresos||0, egr=d.egresos||0, bal=d.balance||0;
  const t = ing>0?Math.round((bal/ing)*100):0;

  document.getElementById('kIngresos').textContent=fmtARS(ing);
  document.getElementById('kIngLabel').textContent=mn+' '+YEAR;
  document.getElementById('kEgresos').textContent=fmtARS(egr);
  document.getElementById('kEgrLabel').textContent=mn+' '+YEAR;
  const bEl=document.getElementById('kBalance');
  bEl.textContent=fmtARS(bal);
  bEl.className='kpi-value '+(bal>=0?'green':'red');
  document.getElementById('kBalBadge').textContent=bal>=0?'Positivo':'Negativo';
  document.getElementById('kBalBadge').className='kpi-badge '+(bal>=0?'up':'down');
  document.getElementById('kTasa').textContent=t+'%';
  document.getElementById('kTasaBadge').textContent=t>=30?'Excelente':t>=15?'Bueno':'Mejorable';
  document.getElementById('pieSub').textContent=mn+' · '+(persona==='todos'?'ingresos vs egresos':persona);
  document.getElementById('catSub').textContent=mn+' · '+(persona==='todos'?'egresos':'egresos de '+persona);
  document.getElementById('psSub').textContent=mn+' · desglose';
  document.getElementById('arcSub').textContent=mn+' · '+(persona==='todos'?'del ingreso':persona);
  document.getElementById('sdIng').textContent=fmtARS(ing);
  document.getElementById('sdEgr').textContent=fmtARS(egr);
  updateArc(t);
  PC.data.datasets[0].data=[ing,egr];
  PC.update();
  document.getElementById('catList').innerHTML=buildCatList(d.byCategoria||{});
  document.getElementById('personaSplit').innerHTML=buildPersonaSplit(d,persona,mn);

  // bar chart
  let bLabels,bIng,bEgr,bBal;
  if(persona==='todos'){
    bLabels=ML;bIng=MI;bEgr=ME;bBal=MB;
  } else {
    const mbp=MBP[persona]||{ingresos:[],egresos:[],balance:[]};
    bLabels=ML;bIng=mbp.ingresos;bEgr=mbp.egresos;bBal=mbp.balance;
  }
  BC.data.labels=bLabels;
  BC.data.datasets[0].data=bIng;
  BC.data.datasets[1].data=bEgr;
  BC.data.datasets[2].data=bBal;
  BC.update();

  // year strip
  const yr=getYearFiltered(persona);
  const yrTasa=yr.ingresos>0?Math.round((yr.balance/yr.ingresos)*100):0;
  document.getElementById('ysIng').textContent=fmtARS(yr.ingresos);
  document.getElementById('ysEgr').textContent=fmtARS(yr.egresos);
  const ysB=document.getElementById('ysBal');
  ysB.textContent=fmtARS(yr.balance);
  ysB.className='ys-val '+(yr.balance>=0?'green':'red');
  document.getElementById('ysBalSub').textContent='tasa de ahorro '+yrTasa+'%';
}

function updMonth(mi){
  currentMonth=parseInt(mi);
  renderAll(currentMonth, currentPersona);
}

function updPersona(p){
  currentPersona=p;
  document.querySelectorAll('.ptab').forEach(t=>t.classList.remove('active','laura','fabio'));
  const active=document.getElementById('tab-'+p.toLowerCase());
  if(active){active.classList.add('active');if(p!=='todos')active.classList.add(p.toLowerCase());}
  renderAll(currentMonth, currentPersona);
}

window.addEventListener('DOMContentLoaded',()=>{
  PC=new Chart(document.getElementById('pieChart').getContext('2d'),{
    type:'doughnut',
    data:{labels:['Ingresos','Egresos'],datasets:[{data:[${monthStats.ingresos},${monthStats.egresos}],backgroundColor:['#00C896','#FF3B5C'],borderColor:['#F8F7F4','#F8F7F4'],borderWidth:4,hoverOffset:6}]},
    options:{responsive:true,maintainAspectRatio:false,cutout:'72%',plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>' '+fmtFull(ctx.raw)}}}}
  });
  BC=new Chart(document.getElementById('barChart').getContext('2d'),{
    type:'bar',
    data:{labels:ML,datasets:[
      {label:'Ingresos',data:MI,backgroundColor:'rgba(0,200,150,.15)',borderColor:'#00C896',borderWidth:1.5,borderRadius:6,borderSkipped:false},
      {label:'Egresos',data:ME,backgroundColor:'rgba(255,59,92,.12)',borderColor:'#FF3B5C',borderWidth:1.5,borderRadius:6,borderSkipped:false},
      {label:'Balance',data:MB,type:'line',borderColor:'#4F6EF7',borderWidth:2,pointRadius:4,pointBackgroundColor:'#4F6EF7',pointBorderColor:'#F8F7F4',pointBorderWidth:2,fill:false,tension:.4}
    ]},
    options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'index',intersect:false},
      plugins:{legend:{position:'top',align:'end',labels:{font:{family:'DM Sans',size:11},usePointStyle:true,pointStyleWidth:8,padding:16,color:'#6B7280'}},
      tooltip:{backgroundColor:'#0D0D0D',titleColor:'#fff',bodyColor:'rgba(255,255,255,.7)',padding:12,cornerRadius:8,callbacks:{label:ctx=>' '+fmtFull(ctx.raw)}}},
      scales:{x:{grid:{display:false},ticks:{font:{family:'DM Sans',size:11},color:'#9CA3AF'}},
      y:{grid:{color:'rgba(0,0,0,.04)'},ticks:{font:{family:'DM Sans',size:10},color:'#9CA3AF',callback:v=>fmtARS(v)},border:{display:false}}}}
  });
  document.getElementById('catList').innerHTML=buildCatList(${JSON.stringify(monthStats.byCategoria||{})});
  document.getElementById('personaSplit').innerHTML=buildPersonaSplit(${JSON.stringify({...monthStats})}, 'todos', '${prevMonthName}');
});
<\/script>
</body>
</html>`;

return [{ json: { html_dashboard: html, prevMonthName, currentMonthName, currentYear } }];
